CREATE INDEX "UserUpgrade_userId_idx" ON public."UserUpgrade" ("userId");

-- UserProgress
CREATE INDEX "UserProgress_userId_idx"            ON public."UserProgress" ("userId");
CREATE INDEX "UserProgress_mode_highestFloor_idx"  ON public."UserProgress" (mode, "highestFloor");

-- QuestionSet
CREATE INDEX "QuestionSet_creatorId_idx" ON public."QuestionSet" ("creatorId");

-- LeaderboardEntry
CREATE INDEX "LeaderboardEntry_questionSetId_gameMode_score_idx"
