CREATE INDEX "LeaderboardEntry_userId_idx" ON public."LeaderboardEntry" ("userId");

-- Question
CREATE INDEX "Question_questionSetId_idx" ON public."Question" ("questionSetId");
CREATE INDEX "Question_subject_idx"       ON public."Question" (subject);
CREATE INDEX "Question_topic_idx"         ON public."Question" (topic);
CREATE INDEX "Question_difficulty_idx"    ON public."Question" (difficulty);

-- GameSession
CREATE INDEX "GameSession_userId_idx"        ON public."GameSession" ("userId");
CREATE INDEX "GameSession_questionSetId_idx" ON public."GameSession" ("questionSetId");
CREATE INDEX "GameSession_gameStatus_idx"    ON public."GameSession" ("gameStatus");

-- Player
CREATE INDEX "Player_gameSessionId_idx" ON public."Player" ("gameSessionId");
CREATE INDEX "Player_userId_idx"        ON public."Player" ("userId");

-- PlayerAnswer
CREATE INDEX "PlayerAnswer_gameSessionId_idx" ON public."PlayerAnswer" ("gameSessionId");
CREATE INDEX "PlayerAnswer_playerId_idx"      ON public."PlayerAnswer" ("playerId");

-- CampaignProgress
CREATE INDEX "CampaignProgress_userId_idx"  ON public."CampaignProgress" ("userId");
CREATE INDEX "CampaignProgress_worldId_idx" ON public."CampaignProgress" ("worldId");

-- BossAttempt
CREATE INDEX "BossAttempt_userId_idx" ON public."BossAttempt" ("userId");
CREATE INDEX "BossAttempt_bossId_idx" ON public."BossAttempt" ("bossId");
